var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아직까지 잠들지 않은 건가.","JPN":"まだ眠っていなかったのか。","ENG":"You're still awake.","TWN":"還沒有睡著嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"날이 늦었네. 계승식이 얼마 남지 않아 조급한 건 이해하나 쉴 때는 쉬어야지.","JPN":"もう遅い。継承式が間近で焦っているのはわかるが、休む時はきちんと休みなさい。","ENG":"It's late. I understand you're anxious with the succession ceremony approaching, but you need to rest too.","TWN":"天色已晚。雖然理解你對即將到來的繼承儀式感到焦慮，但該休息的時候還是要休息。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"시시각각 죽어가는 동료들의 목소리가 아직 귓가에 선명합니다.","JPN":"刻一刻と、死んでいく仲間たちの声がまだ耳に残っています。","ENG":"The voices of fallen comrades still echo in my ears.","TWN":"時時刻刻，耳邊仍清晰地迴響著同伴們逐漸逝去的聲音。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 시간을 말미암아 한 명이라도 더 구할 수 있다면… 그리 하는 것이 귀족으로서의 의무겠지요.","JPN":"私の時間を使い、一人でも多く救うことができるのなら……そうするのが貴族としての義務でしょう。","ENG":"If staying awake a little longer could help save even one more life... then it's a duty I must bear as a noble.","TWN":"如果能在我的時間裡多救一個人……那就是作為貴族的義務吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……ああ。","ENG":"...I see.","TWN":"……是啊。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"당신이 그렇다면 말릴 수는 없지.","JPN":"君がそうしたいのなら止めることなどできない。","ENG":"If that's how you feel, I won't stop you.","TWN":"如果你堅持的話，我也無法阻止你。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"먼저 잠드셔도 돼요, 알렌.","JPN":"先にお休みください、アレン。","ENG":"You're free to rest first, Allen.","TWN":"你可以先睡，艾倫。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"당신이 백작령에 힘을 쓴 탓에 요즘 통 볼 시간이 없지 않았나.","JPN":"君が伯爵領の仕事に励むあまり、最近は顔を合わせる時間もなかったじゃないか。","ENG":"You've been too busy managing the County to spend time together.","TWN":"你最近都在伯爵領地忙，我都沒什麼見到你。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"제국의 참모에게 조언을 구할 기회는 흔치 않으니, 잠깐은 괜찮겠지.","JPN":"帝国の参謀から助言してもらう機会は貴重だ。少しぐらいいいだろう。","ENG":"It's not often I get the advice of the Empire's top strategist, so I'll keep you a while longer.","TWN":"向帝國的參謀尋求建議的機會不常有，晚點睡沒問題。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그레이스. 자네도 알겠지만 북동쪽 페네리테 방어선이 침공당했네.","JPN":"グレース。君も知っているだろうが、北東のフェネリテ防御線が攻撃された。","ENG":"Grace. As you know, the northeastern Penelite defense line was breached.","TWN":"葛瑞絲。你也知道，東北方向的佩內裡特防線遭到了入侵。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전황은 점점 불리해지고 있어. 전하께서도 결단이 필요하다고 생각하시는 것 같더군.","JPN":"戦況は徐々に不利になっている。殿下も決断が必要だとお考えになっているようだ。","ENG":"The tide of battle is turning against us. His Majesty believes decisive action is needed.","TWN":"戰況越來越不利了。看來殿下也認為需要做出決斷了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"역시, 무구를 만드는 동안이라도 구원기사단과 함께 움직이는 편이 좋지 않겠나?","JPN":"武具を作っている間だけでも救世騎士団と行動を共にしてはどうだろうか？","ENG":"Shouldn't we coordinate with the Knights of Redemption, even while the Armament is still being forged?","TWN":"果然，在製作武具期間，還是和救贖騎士團一起行動比較好吧？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"각각의 방어선을 지키는 것조차 버거운 상황에 어찌 전력을 합치겠습니까?","JPN":"各々の防御線を守ることすら手に負えない状況下で、どうして戦力を一つにまとめるのですか。","ENG":"When each front is barely holding, how could we consolidate our forces?","TWN":"我們連各自的防線都難以守住，怎麼能合力呢？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는 대의를 위해서라는 이유로 신민들의 희생을 강요하고 싶지 않습니다.","JPN":"私は大義のためという理由で、臣民に犠牲を強要したくはないのです。","ENG":"I won't demand sacrifices from the people in the name of the greater good.","TWN":"我不想以大義為由強迫臣民犧牲。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그것이 별의 인도라면 따르겠네.","JPN":"それが星の導きなら従おう。","ENG":"If it's the guidance of the stars, I'll follow it.","TWN":"如果那是星之引導，我會跟隨。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만 제국이 구원자를 찾은 시점에서 백작가의 전승이 큰 의미가 있을지는 의문이군.","JPN":"だが、帝国が救世主を見出した時点で伯爵家の伝承が果たして意味があるのかは疑問だ。","ENG":"Still, now that the Empire has found its Savior, I wonder if the legend of the Count's house holds any weight.","TWN":"但是在帝國找到了救贖主的情況下，伯爵家的傳承是否還有重要意義，令人懷疑。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"솔직한 심정으로 별의 무구가 전황에 큰 변화를 가져올 것 같지는 않아.","JPN":"正直、星の武具が戦況を大きく変えられるとは思えない。","ENG":"To be frank, I doubt the Star Armament alone can shift the course of this war.","TWN":"說實話，我覺得星之武具不會對戰況帶來太大的變化。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"구원자의 흑색제복에는 여러 의미가 있지만, 그것은 또한 공허한 밤하늘을 의미합니다.","JPN":"救世主の黒い礼装には色々な意味がありますが、それはまた虚ろな夜空を意味します。","ENG":"The black uniform of the Savior carries many meanings, but above all, it symbolizes the empty night sky.","TWN":"救贖者的黑色制服有著多重的意義，它也象徵著空虛的夜空。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"모든 것을 품을 수 있음에도 제 혼자서는 빛을 낼 수 없어 별빛을 필요로 하지요.","JPN":"すべてを抱くことができるにも関わらず、自分だけでは光を発することができないので、星の光を必要とするのです。","ENG":"It can embrace all things, yet cannot shine on its own. It needs starlight.","TWN":"雖然能夠包容一切，但自身無法發光，所以需要星光。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"레이의 힘만으로는 마왕을 쓰러트릴 수 없다는 건가?","JPN":"レイの力だけでは魔王を倒せないということか？","ENG":"So you're saying Ray can't defeat the Demon Lord alone?","TWN":"僅憑雷伊的力量無法擊敗魔王嗎？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"전승에 따르면 열두 별빛이 모인 순간 인도자의 조율 아래 흑색제복은 본래의 모습을 되찾는다고 합니다.","JPN":"伝承によれば、12の星の光が集まった瞬間、導き手の調律のもとに黒い礼装は本来の姿を取り戻すそうです。","ENG":"According to legend, when the twelve starlights converge under the Guide's harmony, the black uniform regains its true form.","TWN":"傳說中，當十二顆星光彙聚之時，在引導者的調和下，黑色制服將恢復原本的樣貌。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"형태 없는 별빛이 어떤 모습을 갖출지는 온전히 구원자의 몫에 달렸으나…….","JPN":"形のない星の光がどんな姿になるのかは、救世主にかかっていますが……","ENG":"What shape that formless starlight takes depends on the Savior alone...","TWN":"無形的星光將呈現何種形態，完全取決於救贖者……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"선대가 남긴 전승이 틀리지 않았다면, 그것이 제국에 가라앉은 어둠을 몰아낼 별빛임은 틀림없겠지요.","JPN":"先代が残した伝承が間違っていないなら、それが帝国に淀む闇を追い払う星の光に違いありません。","ENG":"But if the legend passed down is true, then that starlight will surely be what drives out the darkness plaguing the Empire.","TWN":"如果祖先留下的傳承沒有錯，那必定是驅散帝國沉寂黑暗的星光。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"무구개방… 확실히, 그 힘이라면 레이의 실력을 뒷받침해줄 수 있겠지.","JPN":"武具開放……確かにその力なら、レイの実力を後押ししてくれるだろう。","ENG":"Unleashing the Armament... If that power supports Ray, it could be a game-changer.","TWN":"武具解放……確實，那股力量可以支持雷伊的實力。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만 자네 말대로 무구가 어떤 형태로 개방될지는 순전히 사용자의 몫에 달렸어.","JPN":"だが君の言うとおり、武具がどんな形で開放されるかは使用者次第だ。","ENG":"But as you said, its final form depends entirely on the wielder.","TWN":"但是正如你所說，武具以何種形式解放完全取決於使用者。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그 녀석의 심성을 생각한다면… 마왕의 숨통을 끊을 형태가 아닐 수도 있지 않겠나?","JPN":"あいつの性格を考えると……魔王にとどめを刺すような形ではない可能性もあるのではないか？","ENG":"And knowing him... it might not be something that can kill the Demon Lord.","TWN":"考慮到那傢伙的性情……也許不會是能扼殺魔王的形態吧？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"알 수 없습니다.","JPN":"わかりません。","ENG":"We don't know.","TWN":"這就不知道了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그러니 조금이라도 더 빠르게 무구를 완성시켜야겠죠.","JPN":"わからないから、一刻でも早く武具を完成させないと。","ENG":"Which is why we must complete the Armament as quickly as possible.","TWN":"所以必須儘快完成武具的製作。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"역시 한숨 돌리는 편이 좋겠군.","JPN":"やはり少し休んだ方が良さそうだ。","ENG":"You really should rest.","TWN":"看來還是稍微喘口氣比較好。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머.","JPN":"あら。","ENG":"Oh my.","TWN":"哎呀。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"자네의 사명감이 투철하다는 건 오래전부터 알고 있었어.","JPN":"君が使命感の強い人だということは昔からわかっていた。","ENG":"I've always known how devoted you are.","TWN":"我知道你的使命感很強。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"허나 누누이 말하지 않았나. 자신을 내던지는 건 모든 것을 쏟아낸 이후여야 한다고.","JPN":"しかし、何度も言っているように、自分の身を犠牲にするのは、持てるすべてを出し切ってからだ。","ENG":"But haven't I said it before? You should only throw yourself into the fire after giving it everything you've got.","TWN":"但是我不是已經說過很多次了嗎。只有在傾盡所有之後，才能捨棄自己。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"알렌도 많이 컸네요. 예전에는 제게 반항 한 번 못했는데.","JPN":"アレンもずいぶん成長しましたね。昔は私に逆らえなかったのに。","ENG":"You've grown, Allen. You couldn't even talk back to me in the old days.","TWN":"你翅膀硬囉。以前從來不敢反抗我呢。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"누가 혹독하게 굴린 덕이지.","JPN":"誰かさんに厳しくこき使われたおかげでね。","ENG":"That's because someone raised me with an iron fist.","TWN":"這都是因為被你壓榨的結果。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 하지만 꽃으로 청혼하던 센스는 그대로인 것 같습니다.","JPN":"ええ。ですが、花を持ってプロポーズするセンスはそのままのようですね。","ENG":"Yes. Though your taste for flower proposals remains the same, it seems.","TWN":"是的。不過用花求婚的情調似乎還是一樣的。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이럴 때는 좀 더 과감하게-.","JPN":"こういう時はもっと大胆に……","ENG":"At times like this, you ought to be a bit bolder–","TWN":"這種時候就要更大膽一點-"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"피곤한 모양이군. 잠시 눈을 붙이는 게 좋겠어.","JPN":"疲れているようだ。しばらく横になった方が良い。","ENG":"You're clearly exhausted. You should close your eyes for a bit.","TWN":"看起來很累呢。最好稍微休息一下。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"얼마 뒤에 깨워줄 테니, 잠깐 동안이라도 쉬게.","JPN":"少ししたら起こすと約束しよう。今は休んでくれ。","ENG":"I'll wake you soon. Just rest for now.","TWN":"我一會兒叫醒你，先休息一下吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"아뇨. 귀족으로서 신민들을 구하기 위한 고통은 감수해야만 합니다.","JPN":"いいえ。貴族として臣民を助けるために、この程度の苦痛は耐えられます。","ENG":"No. A noble must bear the pain of saving her people.","TWN":"不。作為貴族，為了拯救臣民必須忍受痛苦。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그들을 위해서라면 당연히 이 한 몸 불살라야겠지요.","JPN":"彼らのためなら当然私が頑張らないといけません。","ENG":"If it's for their sake, then burning myself out is a small price to pay.","TWN":"為了他們，我當然願意獻出這條命。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"너무 멀리만을 바라본 탓에 주변을 둘러보지는 못했나 보군.","JPN":"君は遠い未来ばかリを見てきたせいか、自分の周りは見えていないようだ。","ENG":"So focused on the horizon that you've forgotten to look around you.","TWN":"看來你只顧著看遠處，卻沒注意到周圍的情況啊。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"설령 그 끝에 세상이 멸망할지 언정…….","JPN":"たとえその先で世界が滅亡するとしても……","ENG":"Even if the world is destroyed in the end...","TWN":"即便最終世界會滅亡……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"우린 희생으로 얼룩진 승리를 쟁취할 생각은 없어.","JPN":"私たちは犠牲まみれの勝利を手にしたいわけじゃないんだ。","ENG":"We don't seek victory stained with sacrifice.","TWN":"我們不打算通過犧牲來贏得勝利。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"여자가 힘들어할 땐 우선 공감해주는 편이 좋아요, 알렌.","JPN":"女が辛い時にはまずは共感してあげるといいですよ、アレン。","ENG":"Allen, when a woman's struggling, you're supposed to empathize with her first.","TWN":"當女生感到困難時，首先要給予共鳴，這樣比較好，艾倫。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"노력해보지.","JPN":"努力してみよう。","ENG":"I'll try my best.","TWN":"我試試看。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"한껏 예민해진 자네가 자고 일어난다면 말이야.","JPN":"一段と敏感になっている君が寝て起きた後にね。","ENG":"After you've had a proper nap.","TWN":"不過是等你睡醒後再說。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예.","JPN":"はい。","ENG":"All right.","TWN":"好。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그럼, 잠시 어깨를 빌리겠습니다.","JPN":"では、少し肩をお借りします。","ENG":"Then let me borrow your shoulder, just for a moment.","TWN":"那麼，我就暫時借用一下你的肩膀吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경.","JPN":"グレース卿。","ENG":"Dame Grace.","TWN":"葛瑞絲小姐。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"목적지에 도착했다고 합니다. 이만 일어나시죠.","JPN":"目的地に着いたようです。起きてください。","ENG":"We've reached our destination. It's time to get up.","TWN":"據說已經到達目的地了。請起來吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……아.","JPN":"……あ。","ENG":"...Ah.","TWN":"……啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"괜찮으십니까?","JPN":"大丈夫ですか？","ENG":"Are you all right?","TWN":"你還好嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 어젯밤 흥이 올라 저도 모르게 과음했나 보네요.","JPN":"はい。昨夜は興奮してうっかり飲みすぎてしまったようです。","ENG":"Yes. I must have overindulged last night.","TWN":"是的。昨晚興致太高，不知不覺就喝多了呢。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"깨워 주셔서 감사합니다.","JPN":"起こしていただき、ありがとうございます。","ENG":"Thank you for waking me.","TWN":"感謝你叫醒我。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"속이 안 좋으시다면 다른 분들을 불러올까요?","JPN":"気分がすぐれないようでしたら、他の方を呼びましょうか？","ENG":"If you're feeling unwell, I can fetch someone else.","TWN":"如果你感覺不舒服，要不要叫其他人來？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"으레 익숙해진 상황이니 괜찮습니다.","JPN":"慣れているので大丈夫です。","ENG":"No need. I'm used to this sort of thing.","TWN":"習慣了這種情況，所以沒關係。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다른 병사들만 일하게 둘 순 없으니 이만 나가보도록 하죠.","JPN":"兵士たちだけ働かせておくわけにはいきません。もう出ましょう。","ENG":"Besides, I can't have the soldiers doing all the work while I lounge around. Let's get moving.","TWN":"不能只讓其他士兵工作，我也該出發了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"원정이라길래 좀 더 고된 여정이 되지 않을까 싶었습니다만.","JPN":"遠征というので、もっと厳しい旅になるのではないかと思っていましたが。","ENG":"I was expecting something more grueling for an expedition, but...","TWN":"本以為遠征會是更艱苦的旅程呢。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_CAR_SHAKE"},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"정말 이런 곳에 거점을 마련하는 겁니까?","JPN":"本当にこんなところに拠点を立ち上げるのですか？","ENG":"Are we really setting up base here?","TWN":"真的要在這種地方建立據點嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 다른 분들에게 듣지 못한 건가요?","JPN":"あら。他の方から聞いていないのですか？","ENG":"Oh my. Didn't the others explain?","TWN":"喔，難道其他人沒有告訴你嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"출정 전, 다른 병사들에게 이번 원정에 관한 이야기를 전해달라 일렀을 텐데요.","JPN":"出征前、他の兵士に今回の遠征について説明するよう言っておいたのですが。","ENG":"Before we set out, I asked the other soldiers to pass along details of the mission.","TWN":"出征前，我應該已經讓其他士兵傳達這次遠征的消息了。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"절 이곳에 데리고 온 건 그레이스 경이시잖습니까.","JPN":"私をここに連れてきたのはグレース卿です。","ENG":"But it was you who brought me here, Dame Grace.","TWN":"把我帶到這裡的是葛瑞絲小姐吧。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"다른 사람에게는 말하지 못할 비밀이 있을 수 있으니, 직접 이야기를 들어야 한다 생각했습니다.","JPN":"他の人には言えない秘密があるかもしれないので、直接話を聞くべきだと思いました。","ENG":"I thought there might be things only I should hear directly from you.","TWN":"因為可能有無法告訴別人的秘密，所以我認為必須親自聽你說。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……그럼 지금까지 목적지도 모른 채 따라오셨던 겁니까?","JPN":"……では、今まで目的地も知らずについて来ていたのですか？","ENG":"...So you've followed me all this way without even knowing the destination?","TWN":"……那麼到現在為止，你都是在不知道目的地的情況下跟著我的嗎?"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그동안 그레이스 경은 병사들의 지휘로 바쁘셨고.","JPN":"今までグレース卿は兵士の指揮で忙しかったですし。","ENG":"You've been busy leading the troops.","TWN":"這段時間你忙於指揮士兵。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"혹여 제가 묻지 않더라도, 언젠가 말씀해주시지 않을까 싶어…….","JPN":"私から聞かずとも、いつかは話してもらえると思っていたもので……","ENG":"I figured you'd tell me when the time was right, even if I didn't ask.","TWN":"即使我不問，我想總有一天你會告訴我的……"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"왜 그러십니까?","JPN":"どうしましたか？","ENG":"Is something wrong?","TWN":"為何不說話？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"푸흡.","JPN":"ぷっ。","ENG":"Pfft.","TWN":"噗哧。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"푸하하하! 이제 보니 에스텔은 참으로 알렌을 빼닮으셨습니다!!","JPN":"あははは！　エステル、本当にアレンにそっくりですね！！","ENG":"Ahahaha! Now that I look at you, you really are just like Allen!","TWN":"哈哈哈！現在看來，艾斯特真是和艾倫一模一樣呢！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이건 이제 착한 걸 넘어 호구의 영역 아닙니까! 푸하하하!!","JPN":"これはもういい子を通り越して間抜けの領域ではありませんか！　あははは！！","ENG":"This isn't just kindness. You're practically a pushover! Ahaha!","TWN":"這已經不是善良，而是傻瓜的境界了吧！哈哈哈！！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"호, 호구…?","JPN":"ま、間抜け……？","ENG":"A p-pushover?","TWN":"喔，傻瓜…？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"너무 기분 나빠 하지 마시지요! 제가 알렌에게 반한 것도 그런 호구 같은 점이었으니!","JPN":"そう気を悪くしないでください！　私がアレンに惚れたのも、そのどこか抜けているところなのですから！","ENG":"Don't take it the wrong way! That's exactly the kind of softness I fell for in Allen!","TWN":"別太不高興嘛！我喜歡上艾倫也是因為他那種傻乎乎的地方！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"풉, 푸흐… 푸하하하!!","JPN":"ぷっ、ぷふっ……あははは！！","ENG":"Pffft... Ahaha!","TWN":"噗，噗…噗哈哈哈！！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아니.","JPN":"いや。","ENG":"Seriously.","TWN":"不。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"대체 언제까지 웃으실 겁니까, 그레이스 경!","JPN":"いったいいつまで笑う気ですか、グレース卿！","ENG":"How long are you going to laugh, Dame Grace?!","TWN":"到底要笑到什麼時候，葛瑞絲小姐！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하다못해 설명을 해준 뒤에 웃으시란 말입니다…!!","JPN":"少なくとも説明をしてから笑ってください……！！","ENG":"At least explain things before bursting out like that...!","TWN":"至少要先解釋一下再笑啊…！！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이런, 부끄럽게도 지조 없는 모습을 보이고 말았네요.","JPN":"ああ、私としたことが。お恥ずかしながら、だらしない姿を見せてしまいましたね。","ENG":"Goodness, how unbecoming of me.","TWN":"哎呀，不好意思，讓你看到我失禮的一面。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이렇게 웃은 게 얼마만인지 모르겠습니다. 혹, 궁중 광대에 관심 없으신지요?","JPN":"こうやって笑ったのはいつぶりでしょう。もしや、宮廷ピエロの職に興味はありませんか？","ENG":"I haven't laughed like that in ages. Are you sure you don't want a career as a court jester?","TWN":"我都不記得有多久沒這樣笑過了。你對宮廷戲班有興趣嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"농담이니 그리 매섭게 보지 마시지요. 궁금하신 내용이라면 설명해드리겠습니다.","JPN":"冗談ですので、そう睨まないでください。気になるなら説明いたしましょう。","ENG":"I jest. Don't glare at me like that.","TWN":"只是個玩笑，不要用那麼可怕的眼神看我。如果你有疑問，我會為你解釋的。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다만 진지를 구축중인 병사들 앞에서 농땡이를 부릴 수도 없는 법이지요.","JPN":"ただ陣地を構築している兵士の前でサボるわけにはいきません。","ENG":"Though, I can't exactly slack off in front of the troops building fortifications.","TWN":"不過，在正在構築陣地的士兵面前偷懶是不行的。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경께서 괜찮으시다면, 잠시 걸으시겠습니까?","JPN":"卿さえよろしければ、少し歩きませんか？","ENG":"If you don't mind, shall we walk a bit?","TWN":"如果你方便的話，可以稍微走一走嗎？"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이쯤이 좋겠군요.","JPN":"ここら辺で良いでしょう。","ENG":"This spot should do.","TWN":"這裡不錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"사방이 트여 비루함이 사라졌으니 이곳이라면 병사들의 눈치를 볼 필요도 없겠습니다.","JPN":"四方が開かれているので、ここなら兵士を気にする必要もありません。","ENG":"The view is clear, no signs of squalor. No need to worry about being seen by the others here.","TWN":"視野開闊，也不需要顧忌士兵們的眼色。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"병사들을 피할 뿐이라면 산을 탈 필요는 없지 않습니까?","JPN":"兵士を避けるだけなら、山に登る必要はないのでは？","ENG":"If you just wanted privacy, you didn't need to climb a mountain.","TWN":"如果只是為了避開士兵，沒必要爬山吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 그것도 이유 중 하나이나, 번거로이 이곳에 온 이유는 따로 있습니다.","JPN":"ふふ。それも理由の一つですが、わざわざここに来た理由は別にあります。","ENG":"That's part of it, but I had another reason for coming here.","TWN":"呵呵，那也是原因之一，不過我來這裡還有更重要的理由。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"보다 뚜렷한 별의 광명을 느껴 감각을 일깨우기 위함이지요.","JPN":"より鮮明な星の光明を感じ、感覚を目覚めさせるためです。","ENG":"I wanted to awaken my senses by feeling the starlight more clearly.","TWN":"為了喚醒感官，感受更為清晰的星光。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"뚜렷하다고 한들 아직 낮이니 별을 관측하기는 힘들 겁니다.","JPN":"鮮明とは言ってもまだ昼間ですし、星の観測は無理なのではないでしょうか。","ENG":"Even if it's clearer here, it's still daytime. You can't see any stars.","TWN":"即便再清晰，現在是白天，觀測星星還是很困難的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저희가 진을 친 곳은 낙후되어 더는 사람이 살지 않는 지역이나.","JPN":"私たちが陣地を築いた場所は老朽化し、もう人が住んでいない地域ですが。","ENG":"This region is uninhabited, long since abandoned.","TWN":"我們紮營的地方是一個落後且無人居住的地區。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"사람의 손이 닿지 않아, 또한 상승점에 위치한 별의 영향력이 지대한 곳입니다.","JPN":"人の手が入らないため、上昇点に位置した星の影響力がとても大きい場所なのです。","ENG":"But because it's untouched by humans and lies at a convergence point, the influence of the stars here is immense.","TWN":"人跡罕至，同時也是位於上升點的星星影響力巨大的地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이곳은 그곳과 인접한 장소이니 별이 보이지 않아도 기운을 느끼기엔 충분하지요.","JPN":"ここはその近くですので、星が見えなくてもオーラを感じるには十分です。","ENG":"We're right near that point. Even without seeing them, you can feel the starlight.","TWN":"這裡是與那地方相鄰的地方，即使看不到星星，也足以感受到氣息。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"장소는… 이쯤이면 되겠군요.","JPN":"さてと……この辺で良いでしょう。","ENG":"It should be... around here.","TWN":"地點……這裡應該可以了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"자, 백작가에서 별빛을 붙잡은 때를 떠올려 보시지요.","JPN":"さあ、伯爵家で星の光を捕まえた時を思い出してください。","ENG":"Now, remember the moment your house first grasped the light of the stars.","TWN":"來吧，回憶一下在伯爵家捕捉星光的時刻吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"처녀자리의 가호를 다룬 경이라면, 황도의 별빛을 느끼는 것도 무리는 아닐 겁니다.","JPN":"乙女座の加護を扱っていた卿なら、黄道の星の光を感じることも不可能ではないでしょう。","ENG":"You've wielded Virgo's blessing. Sensing the Zodiac's starlight shouldn't be impossible.","TWN":"如果是掌握了處女座之守護，感受到十二宮的星光也不是什麼難事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다. 별다른 감각이 느껴지진 않는군요.","JPN":"申し訳ありません。特に何も感じられません。","ENG":"I'm sorry. I don't feel anything.","TWN":"抱歉，我沒有感覺到什麼特別的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"흐음… 아직 경께서 별빛을 받아들일 준비가 덜 된 모양입니다.","JPN":"そうですか……卿はまだ星の光を受け入れる準備ができていないようですね。","ENG":"Hmm... It seems you're not quite ready to accept the starlight yet.","TWN":"嗯…看來你還沒有準備好接受星光的洗禮。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"괜찮습니다. 이 또한 시간이 해결해주겠죠.","JPN":"大丈夫です。これも時が解決してくれるでしょう。","ENG":"That's all right. Time will solve that.","TWN":"沒關係。這種事情時間會解決的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"본제로 돌아와, 앞서 말했듯 저희는 별의 기운이 지대한 곳에 진을 쳤습니다.","JPN":"本題に戻りますと、先程もお話ししましたように、私たちは星のオーラがとても強いところに陣地を築きました。","ENG":"But back to the topic at hand. As I said, we set up camp in a location saturated with starlight.","TWN":"回到正題，正如之前所說，我們在星辰之力極為強大的地方紮營。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"조화의 내행성이 일면을 통과하는 순간.","JPN":"調和の内惑星が一面を通り過ぎる瞬間。","ENG":"When the planet of Harmony passes over this area,","TWN":"和諧的內行星穿過日面的瞬間。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"처서의 별로부터 뿜어져 나온 기운을 별빛에 품어 무구를 벼려내기 위함이지요.","JPN":"処暑の星から発せられたオーラを星の光に込め、武具を鍛えるためです。","ENG":"we'll use the energy released from Virgo's star to forge the Armament with starlight.","TWN":"為了將從處暑之星散發出的氣息注入星光中，捨棄武具。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……쉽게 말해, 전에 말하셨던 황도의 관측점이 이곳이라는 의미군요.","JPN":"ようするに、ここがさっきおっしゃっていた黄道の観測点なのですね。","ENG":"...In other words, this is the observation point of the zodiac you mentioned earlier.","TWN":"……簡單來說，就是你之前提到的十二宮觀測點在這裡的意思吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"처음부터 무구를 만드는 것이 목적이었다 말해 주셨다면 이런 오해는 없었을 겁니다.","JPN":"最初から武具を作ることが目的だと話してくださったなら、こんな誤解はしなかったはずです。","ENG":"If you'd just told me from the start that the goal was to create an Armament, none of this confusion would've happened.","TWN":"如果一開始就告訴我目的是製造武具，就不會有這樣的誤會了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그야 에스텔이 저를 거짓말쟁이로 여기셨잖아요?","JPN":"それは、エステルが私を嘘つきと思っていたからではないですか。","ENG":"Well, you did think I was a liar, didn't you?","TWN":"因為艾斯特把我當成了騙子，不是嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"사흘 전으로 돌아가 같은 사실을 일렀다면, 분명 찌그러진 로스콘 같은 표정을 지으셨을 겁니다.","JPN":"3日前に戻り同じことを知らせていたら、きっとぐしゃぐしゃになったロスコンのようなお顔になっていたと思いますわ。","ENG":"If I'd told you the truth three days ago, you'd have made a face like a squashed roscón.","TWN":"如果回到三天前告訴你同樣的事實，你肯定會露出我是騙子的表情。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그 정도는 아닙니다.","JPN":"そこまでではありません。","ENG":"It wouldn't have been that bad.","TWN":"沒到那個程度。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만… 부정했으리라는 사실은 반박하기 힘들군요.","JPN":"ですが……否定したかもしれないということについては反論できませんね。","ENG":"Though... I probably would've denied it.","TWN":"但…我不完全否認。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 목적을 불분명하게 밝힌 것이 제 나름의 복수였으니 무승부로 치지요.","JPN":"ふふ。目的をはっきり明かさなかったのが私なりの復讐でしたので、おあいこです。","ENG":"Haha. Then let's call it even. My vague answers were my way of getting back at you.","TWN":"呵呵。沒說清楚目的，算是我對你的報復，我們就當扯平了吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"분명 이해하신 것이 맞습니다.","JPN":"そして、卿の理解で合っています。","ENG":"But you've understood now, haven't you?","TWN":"你確實理解了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이번 원정은 마지막 남은 별의 무구인 <color=#ffd34c>버고 소드</color>의 완성.","JPN":"今回の遠征の目的は最後の星の武具である<color=#ffd34c>ヴァルゴソード</color>の完成。","ENG":"This expedition is to complete the final Star Armament, the <color=#ffd34c>Virgo Sword</color>.","TWN":"這次遠征是最後一顆星的聖遺物<color=#ffd34c>布林加夫之劍</color>的完成。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"더 나아가, 그를 통해 제국 계승식을 무사히 성료하는 것이니까요.","JPN":"さらには、それを通じて帝国の継承式を無事完了させることですから。","ENG":"And through that, to ensure the Imperial succession ceremony is carried out safely.","TWN":"更進一步，通過它順利完成帝國繼承儀式。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제국 계승식이라면…….","JPN":"帝国の継承式というと……","ENG":"The Imperial succession ceremony...","TWN":"如果是帝國繼承儀式的話……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"세계가 선택한 영웅에게 제국의 유구한 고유무장을 건네는 의식입니다.","JPN":"世界が選んだ英雄に帝国の悠久なる固有武装を渡す儀式です。","ENG":"It's the rite where the Empire's sacred Unique Gear is entrusted to the hero chosen by the world.","TWN":"這是將帝國悠久的專屬武裝交給世界所選英雄的儀式。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"인도자의 조율 아래, 황족을 대표하는 <color=#ffd34c>제국의 태양</color>과 교회를 상징하는 <color=#ffd34c>성설한 달.</color>","JPN":"導き手の調律のもとに、皇族を代表する<color=#ffd34c>帝国の太陽</color>と、教会を象徴する<color=#ffd34c>聖なる月</color>。","ENG":"Under the Guide's harmony, the <color=#ffd34c>Empire's sun</color> represented by the royal family and the <color=#ffd34c>sacred moon</color> symbolizing the church.","TWN":"在引導者的調和下，代表皇族的<color=#ffd34c>帝國太陽</color>與象徵教會的<color=#ffd34c>神聖之月。</color>"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그리고 별의 무구의 선택을 받은 열두 기사가 새로운 희망의 도래를 천명하는 것이지요.","JPN":"そして星の武具に選ばれた12騎士が、新しい希望の到来を宣言するのです。","ENG":"And the twelve knights chosen by the Star Armaments all declare the arrival of a new hope.","TWN":"而被星之武具選中的十二騎士則宣告了新希望的到來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만 무구를 만드는 것만이라면 이 정도의 병력이 필요할지 의문이군요.","JPN":"でも、武具を作ることだけのためにこれほどの兵力が必要なのですか？","ENG":"But if it's just about creating the Armament, do we really need this many troops?","TWN":"不過如果只是製造武具的話，是否需要這樣的兵力還真是個疑問呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"괴수들이 자신에게 없는 가능성을 찾아 헤맨다는 것 또한 말씀드리지 않았습니까?","JPN":"怪獣は自分にはない可能性を探し回っているということもお話ししましたね？","ENG":"Didn't I mention it before? Monsters wander in search of potential they lack.","TWN":"我不是告訴過你，怪獸們也在尋找自己沒有的可能性嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"별의 무구는 별빛이라는 가능성을 직접 무구에 담는 행위입니다.","JPN":"星の武具は星の光という可能性を直接武具に込める行為です。","ENG":"Forging a Star Armament is the act of containing possibilities, starlight, within a weapon.","TWN":"星之武具是將星光直接融入武具中的行為。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"때문에 무구가 완성되기 전까지 온갖 괴수들이 제 목숨을 노리지요.","JPN":"そのため、武具が完成されるまであらゆる怪獣が私の命を狙ってくるのです。","ENG":"Naturally, until it's complete, I'll be targeted constantly.","TWN":"因此，在武具完成之前，各種怪物都會盯上我的性命。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……위험한 일을 태연하다는 듯 말씀하시는군요.","JPN":"危険な話をずいぶん平然とおっしゃるのですね。","ENG":"You talk about all this danger so casually...","TWN":"……你說起危險的事情時，似乎毫不在意呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 병사들이 목숨을 걸고 저를 지켜주고 있으니까요.","JPN":"私の兵士たちが命をかけて守ってくれていますから。","ENG":"Because my soldiers are risking their lives to protect me.","TWN":"因為我的士兵們正在拼命保護我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저 또한 그들을 믿으니, 제가 불안에 떨 요소는 어디에도 없습니다.","JPN":"私もまた彼らのことを信頼していますので、不安がる理由などどこにもありません。","ENG":"And I trust them, so there's nothing for me to fear.","TWN":"我也相信他們，所以我沒有任何不安的理由。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경. 무구를 만드는데 시간이 얼마나 필요하십니까?","JPN":"グレース卿。武具を作るのにどれくらいの時間がかかるのですか？","ENG":"Dame Grace. How long will it take to forge the Armament?","TWN":"葛瑞絲，製作武具需要多長時間？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"별빛이 선명한 시간대에 작업이 용이하니, 오늘부터 시작하면 나흘은 걸리겠군요.","JPN":"星の光が鮮明な時間帯は作業がしやすいので、今日から始めれば4日はかかるでしょうか。","ENG":"It's best to work when the starlight is strongest. If we start today, it'll take four days.","TWN":"在星光明亮的時段工作比較方便，從今天開始的話，大概需要四天。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무슨 문제라도 있으십니까?","JPN":"何か問題でも？","ENG":"Is something wrong?","TWN":"有什麼問題嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"별의 가호가 있던 이전까지는 알 수 없었으나, 저번 전투로 확신했습니다.","JPN":"星の加護があった頃はわからなかったのですが、この前の戦闘で確信しました。","ENG":"Until now, I didn't realize it because I had the Blessing of the Stars. But after the last battle, I finally understood.","TWN":"雖然之前無法確定星星的守護，但通過上次的戰鬥我確信了這一點。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금까지 저는 가호에 의존한 싸움만을 해왔다는 걸요.","JPN":"今まで私は加護に頼った戦い方ばかりしてきたということを。","ENG":"I've been relying entirely on that blessing.","TWN":"直到現在，我一直依賴守護來戰鬥。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그러니 그레이스 경만 괜찮으시다면 제게 검을 알려주셨으면 합니다.","JPN":"ですので、グレース卿さえよろしければ、私に剣術を教えていただけませんか。","ENG":"So if you'll allow it, I'd like you to teach me how to wield a sword.","TWN":"所以，如果葛瑞絲小姐不介意的話，請教我劍術吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"더는…….","JPN":"もう……","ENG":"I don't want to...","TWN":"我已經……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"더 이상, 누군가 죽는 모습을 보고 싶지 않아요.","JPN":"もうこれ以上、誰かが死ぬ姿を見たくないのです。","ENG":"I don't want to watch anyone else die.","TWN":"不想再看到有人死去了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 교육방식은 꽤나 엄합니다만, 괜찮으시겠습니까?","JPN":"私の教育方針はとても厳しいですが、よろしいですか？","ENG":"My teaching methods are rather strict. Are you sure?","TWN":"我的教育方式相當嚴格，你能接受嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예.","JPN":"はい。","ENG":"Yes.","TWN":"可以。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"바라던 바입니다.","JPN":"望むところです。","ENG":"I wouldn't have it any other way.","TWN":"正是我所期望的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};